class EntropyCalibrator(trt.IInt8EntropyCalibrator2):
    def __init__(self, data_loader, cache_file="calibration.cache"):
        super().__init__()
        self.data_loader = iter(data_loader)
        self.cache_file = cache_file
        self.device_input = None

    def get_batch_size(self): return 8

    def get_batch(self, names):
        try:
            batch = next(self.data_loader).cuda()
            import pycuda.driver as cuda
            self.device_input = cuda.mem_alloc(batch.nbytes)
            cuda.memcpy_htod(self.device_input, batch.numpy())
            return [int(self.device_input)]
        except StopIteration:
            return None

