import tensorrt as trt
import numpy as np
from collections import deque

class ProdProfiler(trt.IProfiler):
    def __init__(self, sla_ms=8.0):
        super().__init__()
        self.sla_ms = sla_ms
        self.total_ms = 0.0

    def report_layer_time(self, layer_name: str, ms: float):
        self.total_ms += ms

    def check_sla(self) -> bool:
        exceeded = self.total_ms > self.sla_ms
        self.total_ms = 0.0
        return exceeded

output_window = deque(maxlen=500)

def monitor_inference(context, output_buf, baseline_mean, baseline_std):
    context.execute_v2(bindings=[...])  # your actual bindings
    out = np.copy(output_buf)
    output_window.append(out.mean())
    if len(output_window) == 500:
        z = abs(np.mean(output_window) - baseline_mean) / (baseline_std + 1e-9)
        if z > 3.0:
            raise RuntimeError(f"Prediction drift detected: Z={z:.2f}")

import subprocess, sys

def trt_ci_gate(onnx_path: str, engine_path: str, p99_budget_ms: float = 5.0):
    subprocess.run([
        "trtexec", f"--onnx={onnx_path}", f"--saveEngine={engine_path}",
        "--fp16", "--optShapes=input:8x3x224x224", "--maxShapes=input:32x3x224x224",
    ], check=True)
    subprocess.run([
        "polygraphy", "run", onnx_path, "--trt", "--onnxrt",
        "--atol=1e-2", "--rtol=1e-2", "--fail-fast",
    ], check=True)
    out = subprocess.run([
        "trtexec", f"--loadEngine={engine_path}", "--percentile=99", "--iterations=500",
    ], capture_output=True, text=True, check=True).stdout
    for line in out.splitlines():
        if "GPU Compute Time" in line and "max =" in line:
            p99 = float(line.split("max =")[1].split("ms")[0].strip())
            if p99 > p99_budget_ms:
                sys.exit(f"Latency gate FAILED: {p99:.2f}ms > {p99_budget_ms}ms")

// Validate input tensor against TensorRT engine binding
void validateInput(nvinfer1::ICudaEngine* engine, const char* name,
                   nvinfer1::Dims actualDims, nvinfer1::DataType actualDtype) {
    auto expectedDtype = engine->getTensorDataType(name);
    auto expectedDims  = engine->getTensorShape(name);

    if (actualDtype != expectedDtype)
        throw std::runtime_error(std::string(name) + ": dtype mismatch");

    for (int i = 0; i < expectedDims.nbDims; ++i) {
        if (expectedDims.d[i] != -1 && expectedDims.d[i] != actualDims.d[i])
            throw std::runtime_error(std::string(name) + ": shape mismatch at dim " + std::to_string(i));
    }
}

// Welford online drift check (per feature)
bool isDrifted(WelfordState& state, float newMean, float sigmaThreshold = 3.0f) {
    float z = std::abs(newMean - state.mean) / (std::sqrt(state.variance) + 1e-8f);
    state.update(newMean);
    return z > sigmaThreshold;
}
